mapper.select:
/* 동일 부모 조직 목록 조회 orgManage.selectParentOrgId */ SELECT ORG_ID, PARENT_ORG_ID, ORG_LEVEL, SORT_ORDER FROM TB_ORG WHERE
PARENT_ORG_ID = #{parentOrgId}
PARENT_ORG_ID IS NULL
AND USE_YN = 'Y' ORDER BY CAST(IFNULL(SORT_ORDER, '0') AS UNSIGNED) ASC, ORG_ID ASC

/* 동일 부모 조직 내 최대 정렬순서 조회 orgManage.selectMaxSortOrderByParentOrgId */
SELECT IFNULL(MAX(CAST(SORT_ORDER AS UNSIGNED)), 0)
FROM TB_ORG
WHERE


            PARENT_ORG_ID = #{parentOrgId}


            PARENT_ORG_ID IS NULL

mapper.update:
/* 동일 부모 조직 정렬순서 일괄 수정 orgManage.updateSiblingSortOrderBatch */
UPDATE TB_ORG
SET SORT_ORDER = CASE ORG_ID

    WHEN #{item.orgId} THEN #{item.sortOrder}

END,
UPDATED_DT = NOW()
WHERE USE_YN = 'Y'
AND


        PARENT_ORG_ID = #{parentOrgId}


        PARENT_ORG_ID IS NULL


AND ORG_ID IN

    #{item.orgId}

/* 조직 삭제 orgManage.deleteOrg */
UPDATE TB_ORG
SET
    USE_YN = 'N',
    UPDATED_DT = NOW()
WHERE ORG_ID = #{orgId}
